refsection.programlisting:
      
s=5;
p=number_primes100();
N=p(s);
u=lowdisc_ldgen(N-1,s,"halton");
u=[zeros(1,s);u];
//
scf();
plot(u(:,s-1),u(:,s),"bo")
lowdisc_plotelembox([p(s-1) p(s)],[1 1])
xlabel(msprintf("X(%d)",s-1));
ylabel(msprintf("X(%d)",s));

      
p=number_primes100();
for s=2:20
    N=p(s-1)*p(s);
    A=1/N;
    mprintf("s=%d, N=%d, A=%.2e\n",s,N,A)
end

      
s=5;
p=number_primes100();
N=prod(p(s-1)*p(s));
u=lowdisc_ldgen(N-1,s,"halton");
u=[zeros(1,s);u];
//
scf();
plot(u(:,s-1),u(:,s),"bo")
lowdisc_plotelembox([p(s-1) p(s)],[1 1])
xlabel(msprintf("X(%d)",s-1));
ylabel(msprintf("X(%d)",s));

      
p=number_primes100();
for b=p(1:30)
    N=b;
    L=1/b;
    mprintf("b=%d, N=%d, L=%.2e\n",b,N,L)
end

      
p=number_primes100();
for b=p(1:30)
    N=b^2;
    A=1/(b^2);
    mprintf("b=%d, N=%d, A=%.2e\n",b,N,A)
end

      
p=number_primes100();
s=10;
k=find(p>=s,1);
b=p(k);
u=lowdisc_ldgen ( b^2-1 , s , "faure" );
scf();
lowdisc_proj2d ( u , [s-1 s] );
lowdisc_plotelembox(b,[1 1])
e=gce();
e.children($).children.mark_size=4;
xlabel(msprintf("X(%d)",s-1));
ylabel(msprintf("X(%d)",s));

      
p=number_primes100();
for b=p(1:30)
    N=b^3;
    V=1/(b^3);
    mprintf("b=%d, N=%d, V=%.2e\n",b,N,V)
end

      
N=1000;
p=number_primes100();
for b=p(1:12)
    d=floor(log(N)/log(b));
    mprintf("b=%d, d=%d\n",b,d)
end
